-- ========================================
-- 3. 里程碑数据 (Milestones)
-- 小樱桃 2021-01-15 出生，现约5.5岁
-- ========================================
INSERT INTO milestones (baby_id, title, description, achieved_at, category, age_in_months, age_in_days, is_preset, celebration_message, created_at, updated_at) VALUES
(1, '第一次翻身', '小樱桃在垫子上用力一翻，成功从仰卧翻到俯卧，爸爸激动地鼓掌', '2021-05-20 14:30:00', 'MOTOR', 4, 125, false, '宝贝太棒了！第一次翻身成功！', NOW(), NOW()),
(1, '第一次独立坐起', '能不用支撑自己坐稳了，虽然还会晃来晃去，但坚持了很久', '2021-08-10 10:15:00', 'MOTOR', 7, 207, false, '小樱桃会坐啦！坐得像个小大人', NOW(), NOW()),
(1, '第一次爬行', '终于学会爬了！目标是床头的玩具熊，爬了整整一米远', '2021-10-05 16:45:00', 'MOTOR', 9, 263, false, '世界那么大，小樱桃要去探索啦！', NOW(), NOW()),
(1, '叫第一声"妈妈"', '晚上临睡前，小樱桃清晰地说出了"妈妈"，妈妈感动得热泪盈眶', '2021-11-08 20:30:00', 'LANGUAGE', 10, 297, false, '妈妈听到这声呼唤，心都化了 ❤️', NOW(), NOW()),
(1, '第一次独立站立', '扶着沙发站起来后，松开了双手，独立站了5秒钟！', '2022-01-18 11:00:00', 'MOTOR', 12, 368, false, '站得高看得远，小樱桃要起飞啦', NOW(), NOW()),
(1, '迈出人生第一步', '从爸爸怀里走向妈妈，摇摇晃晃地走了6步！', '2022-03-22 15:20:00', 'MOTOR', 14, 431, false, '人生第一步，走向妈妈的怀抱 ❤️', NOW(), NOW()),
(1, '说出完整短句', '指着桌上的苹果清晰地说"妈妈，我要吃苹果"，语言能力大爆发！', '2022-06-15 12:00:00', 'LANGUAGE', 17, 516, false, '语言能力大爆发！会表达自己的需求了', NOW(), NOW()),
(1, '第一次自己用勺子吃饭', '虽然弄得满桌都是米饭，但成功把饭送进了嘴里！', '2022-08-20 18:00:00', 'SELF_CARE', 19, 582, false, '自己动手，丰衣足食！虽然战场有点乱 😂', NOW(), NOW()),
(1, '学会骑平衡车', '在小区广场上骑平衡车飞驰，转弯已经很熟练了', '2023-04-10 09:30:00', 'MOTOR', 27, 815, false, '风一样的小女孩！平衡感超棒', NOW(), NOW()),
(1, '认识10种以上颜色', '能准确说出红色、橙色、黄色、绿色、蓝色、紫色、粉色、白色、黑色、灰色', '2023-09-05 16:00:00', 'COGNITIVE', 32, 963, false, '小小色彩鉴赏家！彩虹的颜色都认识', NOW(), NOW()),
(1, '第一次自己穿衣服', '自己穿上了T恤和裤子，虽然前后穿反了，但精神可嘉！', '2023-12-20 08:15:00', 'SELF_CARE', 35, 1069, false, '自己的事情自己做！小樱桃长大啦', NOW(), NOW()),
(1, '学会写自己的名字', '在画板上一笔一画写出了"小樱桃"三个字，虽然有点歪歪扭扭', '2024-06-15 10:30:00', 'FINE_MOTOR', 41, 1247, false, '会写自己名字了！离小学生又近了一步', NOW(), NOW()),
(1, '第一次上台表演', '幼儿园元旦晚会上表演舞蹈《小星星》，一点也不怯场', '2025-01-10 19:00:00', 'SOCIAL', 48, 1456, false, '舞台上的小明星！自信大方', NOW(), NOW()),
(1, '学会跳绳', '从零开始练习，现在已经能连续跳20个了', '2025-06-20 17:30:00', 'MOTOR', 53, 1617, false, '跳绳小能手！运动能力越来越强', NOW(), NOW()),
(1, '独立读完一本绘本', '自己捧着《猜猜我有多爱你》从头读到尾，还会给爸爸妈妈讲故事', '2025-09-15 20:00:00', 'COGNITIVE', 56, 1704, false, '阅读小达人！已经能独立阅读绘本了', NOW(), NOW());

-- ========================================
-- 4. 成长记录 (Growth Records)
-- ========================================
INSERT INTO growth_records (baby_id, type, title, content, media_urls, tags, created_by, location, weather, mood, view_count, like_count, created_at, updated_at) VALUES
(1, 'DIARY', '第一次去动物园', '今天带小樱桃去了野生动物园，看到长颈鹿的时候她兴奋得跳了起来。喂了羊驼，还看了海狮表演。回家的路上一直在模仿猴子叫，太可爱了！', '["/uploads/zoo_1.jpg","/uploads/zoo_2.jpg"]', '["动物园","亲子游","周末"]', 1, '上海野生动物园', '晴朗', '开心', 128, 23, '2022-05-01 15:30:00', NOW()),
(1, 'PHOTO', '小樱桃的涂鸦作品', '3岁的小樱桃画了一幅"全家福"，虽然看起来像一堆彩色线条，但她说最上面的是妈妈，中间是爸爸，最小的是自己。在孩子的眼里，家就是彩色的吧 🎨', '["/uploads/art_20230315.jpg"]', '["涂鸦","艺术","全家福"]', 1, '家里', NULL, '开心', 256, 45, '2023-03-15 10:00:00', NOW()),
(1, 'VIDEO', '公园里放风筝', '春天的午后，在世纪公园放风筝。小樱桃自己拉着风筝线跑了很久，风筝飞得特别高。笑声响彻整个公园～', '["/uploads/kite_video.mp4"]', '["放风筝","春天","户外"]', 1, '世纪公园', '微风', '兴奋', 189, 34, '2023-08-20 14:00:00', NOW()),
(1, 'MILESTONE', '学会游泳啦', '报了暑期游泳班，从害怕水到现在能憋气游5米远。教练夸她学得最快，是个勇敢的小姑娘！', '["/uploads/swim_1.jpg","/uploads/swim_2.jpg"]', '["游泳","暑假","新技能"]', 1, '游泳馆', NULL, '自豪', 312, 56, '2024-07-10 11:00:00', NOW()),
(1, 'DIARY', '幼儿园第一天', '今天是入园第一天，原本担心她会哭，结果小樱桃背着小书包头也不回就走了，倒是妈妈在门口偷偷抹眼泪。老师说她在幼儿园很乖，还帮老师收拾玩具。', '["/uploads/kindergarten_1.jpg"]', '["幼儿园","成长","第一天"]', 1, '阳光幼儿园', '晴', '开心', 445, 78, '2024-09-01 08:30:00', NOW()),
(1, 'PHOTO', '下雪天堆雪人', '今年冬天下了好大的雪，在院子里堆了一个大雪人。小樱桃给雪人戴上了自己的围巾和帽子，还找了树枝当手臂。虽然手冻得通红，但玩得特别开心！', '["/uploads/snowman_2025.jpg"]', '["雪人","冬天","玩雪"]', 1, '小区花园', '大雪', '兴奋', 267, 52, '2025-01-25 10:30:00', NOW()),
(1, 'VOICE', '小樱桃唱《小星星》', '幼儿园学了新歌，回家一直唱给我们听。虽然有几个音跑调了，但认真唱歌的样子真的太治愈了。录下来留作纪念。', '["/uploads/twinkle_star.mp3"]', '["唱歌","童声","治愈"]', 1, '家里', NULL, '开心', 534, 102, '2025-04-18 19:30:00', NOW()),
(1, 'MILESTONE', '成功骑两轮自行车', '拆掉了辅助轮，爸爸扶着跑了几圈后，突然就自己会骑了！从此家里多了一个追风少女。', '["/uploads/bike_1.jpg","/uploads/bike_2.mp4"]', '["自行车","新技能","勇敢"]', 1, '小区广场', '晴', '自豪', 389, 67, '2025-10-05 16:00:00', NOW()),
(1, 'PHOTO', '春天郊游野餐', '和爸爸妈妈一起去植物园春游，带了三明治、水果和果汁。小樱桃帮忙铺野餐垫、分食物，是个能干的小帮手。樱花树下拍了好多美照！', '["/uploads/picnic_20260320_1.jpg","/uploads/picnic_20260320_2.jpg","/uploads/picnic_20260320_3.jpg"]', '["春游","野餐","亲子"]', 1, '植物园', '晴朗', '开心', 198, 41, '2026-03-20 12:00:00', NOW()),
(1, 'VIDEO', '六一儿童节舞蹈表演', '幼儿园六一汇演，小樱桃和同学们表演了舞蹈《祖国的花朵》。穿着粉色裙子，化了妆，在舞台上自信地跳舞，观众掌声不断！', '["/uploads/children_day_2026.mp4"]', '["六一","表演","舞蹈"]', 1, '幼儿园礼堂', NULL, '兴奋', 567, 123, '2026-06-01 09:30:00', NOW()),
(1, 'PHOTO', '暑假海边旅行', '第一次看到大海，小樱桃光着脚丫在沙滩上奔跑，捡了好多贝壳。还勇敢地套着游泳圈在海里扑腾，被浪花拍了一下也不怕，笑着说"好好玩"！', '["/uploads/beach_202607_1.jpg","/uploads/beach_202607_2.jpg","/uploads/beach_202607_3.jpg","/uploads/beach_202607_4.jpg"]', '["暑假","海边","旅行","贝壳"]', 1, '三亚亚龙湾', '晴', '兴奋', 423, 89, '2026-07-10 15:00:00', NOW()),
(1, 'DIARY', '学会做简单早餐', '周末早上，小樱桃说要给爸爸妈妈做早餐。在指导下切了香蕉、倒了牛奶、烤了面包。虽然动作慢悠悠的，但吃起来特别香！', NULL, '["家务","独立","暖心"]', 1, '家里', '晴', '骄傲', 156, 37, '2026-07-12 08:30:00', NOW());

