INSERT INTO education_plans (baby_id, name, description, category, status, start_date, end_date, target_age_months, difficulty_level, goals, progress_percentage, created_by, created_at, updated_at) VALUES
(1, '语言表达能力提升计划', '通过故事讲述、角色扮演和日常对话，提升小樱桃的语言表达能力和逻辑思维能力', 'LANGUAGE', 'ACTIVE', '2026-01-01', '2026-12-31', 65, 2, '["能够完整讲述一个故事","学会使用关联词造句","能清晰表达自己的感受和需求","积累100个新词汇"]', 60, 1, NOW(), NOW()),
(1, '数学思维启蒙', '通过游戏和生活场景，培养数学逻辑思维和数感', 'MATH', 'ACTIVE', '2026-03-01', '2026-09-30', 64, 2, '["掌握20以内加减法","认识基本几何图形","理解数量守恒概念","学会简单分类和排序"]', 45, 1, NOW(), NOW()),
(1, '创意美术启蒙', '通过绘画、手工和欣赏名画，培养审美能力和创造力', 'ART', 'ACTIVE', '2026-02-01', '2026-08-31', 63, 1, '["能画出有主题的画面","学会使用3种以上绘画工具","完成10件手工作品","培养色彩搭配感"]', 70, 1, NOW(), NOW()),
(1, '运动能力综合发展', '通过多种运动游戏，提升大运动协调能力和身体素质', 'MOTOR', 'ACTIVE', '2026-04-01', '2026-10-31', 64, 2, '["学会连续跳绳30个","能拍球100下以上","掌握立定跳远技巧","喜欢参加户外运动"]', 35, 1, NOW(), NOW()),
(1, '社交情商培养', '通过集体活动和社交游戏，学会与人相处和管理情绪', 'SOCIAL', 'ACTIVE', '2026-01-15', '2026-12-31', 63, 2, '["能主动与小朋友分享玩具","学会用语言表达情绪","懂得基本礼貌用语","能参与团队合作游戏"]', 55, 1, NOW(), NOW()),
(1, '音乐素养培养', '通过唱歌、节奏游戏和乐器体验，培养音乐感知能力', 'MUSIC', 'PAUSED', '2025-09-01', '2026-06-30', 60, 1, '["学会5首儿童歌曲","能跟随节奏打拍子","认识简单乐谱符号","体验3种以上小乐器"]', 80, 1, NOW(), NOW()),
(1, '自然科学探索', '通过观察自然和简单实验，培养科学思维和探索精神', 'COGNITIVE', 'DRAFT', '2026-07-01', '2026-12-31', 66, 3, '["养一盆植物并记录生长","认识20种常见动植物","完成5个简单科学小实验","理解四季变化规律"]', 10, 1, NOW(), NOW()),
(1, '幼小衔接准备', '为进入小学做全面准备，包括学习习惯、自理能力和知识储备', 'COGNITIVE', 'COMPLETED', '2025-09-01', '2026-06-30', 56, 3, '["能专注学习20分钟","学会正确握笔姿势","认识100个常用汉字","能独立整理书包"]', 100, 1, NOW(), NOW());

-- ========================================
-- 6. 教育活动 (Education Activities)
-- ========================================
INSERT INTO education_activities (education_plan_id, name, description, type, status, scheduled_time, actual_start_time, actual_end_time, duration_minutes, materials, instructions, notes, rating, completion_percentage, created_at, updated_at) VALUES
-- 语言表达能力提升计划 (plan_id=1)
(1, '故事大王', '让小朋友选择一个故事讲给家人听，锻炼表达能力和记忆力', 'LEARNING', 'COMPLETED', '2026-01-10 10:00:00', '2026-01-10 10:05:00', '2026-01-10 10:30:00', 25, '绘本《三只小猪》', '先和孩子一起读故事，然后鼓励她用自己的话讲出来，可以加上动作和表情', '小樱桃完整讲完了故事，还模仿了大灰狼的声音，非常有创意！', 5, 100, NOW(), NOW()),
(1, '周末趣事分享', '鼓励孩子用完整的句子描述周末发生的有趣事情', 'SOCIAL', 'COMPLETED', '2026-01-17 19:00:00', '2026-01-17 19:05:00', '2026-01-17 19:20:00', 15, NULL, '晚餐后家庭分享时间，每个人轮流说一件今天最开心的事', '小樱桃说去公园喂鸽子最开心，描述了鸽子的颜色和动作', 4, 100, NOW(), NOW()),
(1, '看图说话', '通过图片引导孩子观察并描述画面内容', 'LEARNING', 'COMPLETED', '2026-02-05 16:00:00', '2026-02-05 16:05:00', '2026-02-05 16:30:00', 25, '看图说话卡片一套', '拿出一张图片，引导孩子观察画面细节，说出画面里有什么、在做什么、心情如何', '能描述出画面中的主要元素，但逻辑顺序还需要加强', 3, 100, NOW(), NOW()),
(1, '小小主持人', '模拟主持小节目，锻炼公众表达能力和自信心', 'LEARNING', 'PENDING', '2026-07-20 10:00:00', NULL, NULL, 30, '玩具麦克风', '让孩子扮演电视主持人，播报天气预报或新闻，可以录制下来', NULL, NULL, 0, NOW(), NOW()),

-- 数学思维启蒙 (plan_id=2)
(2, '超市小当家', '在超市中学习数字、价格和简单的加减法', 'GAME', 'COMPLETED', '2026-03-05 10:00:00', '2026-03-05 10:10:00', '2026-03-05 11:00:00', 50, '购物清单、零钱', '给孩子20元预算，让她帮忙挑选商品并计算总价，学习简单的加减', '小樱桃很认真地比较价格，最后成功买到了想要的零食', 5, 100, NOW(), NOW()),
(2, '积木搭建与分类', '通过积木游戏学习形状、颜色分类和简单计数', 'GAME', 'COMPLETED', '2026-03-20 15:00:00', '2026-03-20 15:05:00', '2026-03-20 15:45:00', 40, '彩色积木一套', '让孩子按颜色和形状分类积木，数一数每种有多少个，搭建不同的结构并计数', '能准确分类和计数，搭建了一座"城堡"还数了用了多少块积木', 5, 100, NOW(), NOW()),
(2, '数字寻宝游戏', '在家里寻找带有数字的物品，学习数字的应用', 'GAME', 'COMPLETED', '2026-04-10 10:30:00', '2026-04-10 10:35:00', '2026-04-10 11:00:00', 25, '便签纸、笔', '在便签纸上写下数字，藏在家里各处，让孩子找到并按顺序排列', '找到了所有数字，能正确排列1-20，还主动要求加码到50', 4, 100, NOW(), NOW()),
(2, '认识钟表', '通过趣味游戏学习认读钟表时间', 'LEARNING', 'IN_PROGRESS', '2026-07-15 16:00:00', '2026-07-15 16:05:00', NULL, 30, '玩具钟表模型', '用玩具钟表教孩子认识整点和半点，结合日常生活时间点来记忆', '初步认识了整点，对半点还需要多加练习', 3, 40, NOW(), NOW()),

-- 创意美术启蒙 (plan_id=3)
(3, '手指画创作', '用手指蘸颜料作画，体验色彩和质感的乐趣', 'CRAFT', 'COMPLETED', '2026-02-10 15:00:00', '2026-02-10 15:05:00', '2026-02-10 15:50:00', 45, '手指画颜料、画纸、围裙', '让孩子用手指蘸颜料自由创作，可以画出动物、花朵等任何想画的', '创作了一幅"春天的花园"，色彩非常丰富！', 5, 100, NOW(), NOW()),
(3, '废物利用手工', '用废旧材料制作有用的物品，培养环保意识和创造力', 'CRAFT', 'COMPLETED', '2026-03-15 14:00:00', '2026-03-15 14:05:00', '2026-03-15 15:00:00', 55, '卫生纸筒、彩纸、胶水、剪刀', '用卫生纸筒做小动物或笔筒，发挥想象力和动手能力', '做了一个小兔子笔筒，现在还放在书桌上用呢', 5, 100, NOW(), NOW()),
(3, '水彩画体验', '学习水彩画的基本技法，感受色彩的流动和融合', 'CRAFT', 'COMPLETED', '2026-04-20 10:00:00', '2026-04-20 10:05:00', '2026-04-20 10:50:00', 45, '水彩颜料、画笔、水彩纸', '先示范简单的色彩渐变，然后让孩子自己尝试画彩虹或风景', '画了彩虹和太阳，水彩的晕染效果让画面很美', 4, 100, NOW(), NOW()),
(3, '黏土造型', '用超轻黏土制作立体造型，锻炼精细动作和空间想象力', 'CRAFT', 'PENDING', '2026-08-05 15:00:00', NULL, NULL, 45, '超轻黏土多色、工具套装', '指导孩子用黏土制作小动物或食物，学习混色和塑形技巧', NULL, NULL, 0, NOW(), NOW()),

-- 运动能力综合发展 (plan_id=4)
