-- ========================================
INSERT INTO family_posts (family_id, author_id, content, images, likes, comments, like_count, comment_count, view_count, post_type, is_pinned, visibility, created_at, updated_at) VALUES
(1, 1, '小樱桃今天在幼儿园学会了折纸飞机，回家后教爸爸折。结果爸爸折的飞得比她的还远，小樱桃不服气地说"我的飞机是宝宝飞机，爸爸的飞机是爸爸飞机，不一样的！"😂😂😂', '["/uploads/paper_plane.jpg"]', '[1]', '[{"userId":1,"username":"yongc","content":"童言无忌最可爱","createdAt":"2026-01-05T20:30:00"}]', 15, 3, 234, 'GENERAL', false, 0, '2026-01-05 19:00:00', NOW()),
(1, 1, '🌟 小樱桃成长里程碑 🌟\n\n今天自己独立读完了一整本《猜猜我有多爱你》！从第一页到最后一页，没有让妈妈帮忙。读完还抱着书说："妈妈，我对你的爱有从地球到月亮那么多！"\n\n我的小女孩真的长大了，爱你❤️', NULL, '[1]', '[{"userId":1,"username":"yongc","content":"太感动了，宝贝真棒！"},{"userId":1,"username":"yongc","content":"这本书是我们最爱的睡前故事"}]', 32, 4, 567, 'MILESTONE', true, 0, '2026-01-15 20:30:00', NOW()),
(1, 1, '周末带小樱桃去了植物园春游，天气特别好。小家伙自己背着小书包，里面装着她"精心准备"的零食——其实主要是她自己想吃的东西😂\n\n樱花正值盛开，拍了好多照片。最开心的是在草地上野餐，小樱桃主动把她的饼干分给旁边的小妹妹，老母亲很欣慰❤️', '["/uploads/spring_outing_1.jpg","/uploads/spring_outing_2.jpg","/uploads/spring_outing_3.jpg"]', '[1]', '[{"userId":1,"username":"yongc","content":"春暖花开，最适合带娃出游了"},{"userId":1,"username":"yongc","content":"小樱桃越来越懂事了"}]', 28, 5, 389, 'PHOTO_ALBUM', false, 0, '2026-03-22 14:00:00', NOW()),
(1, 1, '求助！小樱桃最近开始对去幼儿园产生抵触情绪，早上起床就说"不想去幼儿园"。问了好几次才说是因为有个小朋友不跟她玩。\n\n想问问有经验的家长们，这种情况怎么引导比较好？需要跟老师沟通吗？', NULL, '[]', '[{"userId":1,"username":"yongc","content":"建议先和老师了解情况，再帮助孩子学会社交技巧"}]', 8, 5, 456, 'QUESTION', false, 0, '2026-04-10 08:00:00', NOW()),
(1, 1, '小樱桃第一次参加钢琴体验课🎹\n\n老师教她弹了一首简单的小星星，虽然小手还不太够力气按键，但节奏感很好！下课后兴奋地说"妈妈我要学钢琴！"\n\n不知道是不是三分钟热度，先观察一段时间再说😄', '["/uploads/piano_lesson.jpg"]', '[1]', '[{"userId":1,"username":"yongc","content":"培养音乐素养很好啊"},{"userId":1,"username":"yongc","content":"可以先体验再决定是否长期学"}]', 21, 4, 345, 'GENERAL', false, 0, '2026-05-08 15:30:00', NOW()),
(1, 1, '🎉 六一儿童节汇演圆满成功！🎉\n\n小樱桃和同学们表演了舞蹈《祖国的花朵》，穿着粉色纱裙，化着淡妆，在舞台上闪闪发光！\n\n排练了一个多月，每天回家都要跳给我们看。今天在舞台上一个动作都没忘，为你的认真和坚持点赞！👍\n\n祝所有的小朋友节日快乐！', '["/uploads/六一表演1.jpg","/uploads/六一表演2.jpg","/uploads/六一表演3.jpg"]', '[1]', '[{"userId":1,"username":"yongc","content":"宝贝太棒了！为你骄傲"},{"userId":1,"username":"yongc","content":"六一快乐！"}]', 45, 8, 678, 'PHOTO_ALBUM', false, 0, '2026-06-01 10:30:00', NOW()),
(1, 1, '小樱桃今天做了一件让我们特别感动的事。\n\n奶奶最近腰不好，小樱桃主动说"我给奶奶捶捶背"。然后爬上沙发，用小拳头认真地给奶奶捶背，一边捶一边问"奶奶好点了吗？"\n\n奶奶眼眶都红了。我们的暖心小棉袄，真的长大了❤️', NULL, '[1]', '[{"userId":1,"username":"yongc","content":"太暖心了！教育得真好"}]', 38, 6, 523, 'GENERAL', false, 0, '2026-06-15 19:00:00', NOW()),
(1, 1, '暑假三亚之旅 Day 1 🏖️\n\n小樱桃第一次见到大海，兴奋得在沙滩上狂奔！捡了一堆贝壳说要送给幼儿园的老师和好朋友。\n\n傍晚在海边餐厅吃海鲜，小家伙自己用筷子吃面条（虽然掉了一半在桌上），但进步巨大！\n\n明天准备去潜水看看热带鱼～', '["/uploads/sanya_1.jpg","/uploads/sanya_2.jpg","/uploads/sanya_3.jpg","/uploads/sanya_4.jpg"]', '[1]', '[{"userId":1,"username":"yongc","content":"三亚的海真美！玩得开心"},{"userId":1,"username":"yongc","content":"小樱桃勇敢！"}]', 52, 7, 789, 'GENERAL', false, 0, '2026-07-10 21:00:00', NOW()),
(1, 1, '整理相册翻到小樱桃刚出生的照片，感叹时间过得太快了。\n\n从一个皱巴巴的小不点，长到现在会唱会跳会讲故事的小姑娘。虽然带娃的路上有辛苦有疲惫，但看到你的笑容，一切都值得了。\n\n谢谢你选择我们做你的爸爸妈妈，宝贝❤️', '["/uploads/baby_compare.jpg"]', '[]', '[]', 19, 0, 312, 'GENERAL', false, 0, '2026-07-14 22:00:00', NOW());

