INSERT INTO ai_chat_messages (chat_session_id, message_type, content, is_helpful, feedback, metadata, created_at, updated_at) VALUES
(1, 'USER', '我家小樱桃最近特别挑食，以前爱吃的蔬菜现在都不吃了，只吃白米饭和肉类。我该怎么办？', NULL, NULL, NULL, '2026-07-10 20:00:00', NOW()),
(1, 'AI', '挑食是幼儿期的常见现象，很多家长都会遇到。建议您：\n1. 不要强迫进食，营造轻松的用餐氛围\n2. 尝试不同的烹饪方式，如把蔬菜做成有趣的形状\n3. 让宝宝参与食材准备过程，增加对食物的兴趣\n4. 建立固定的用餐时间和零食规则\n您宝宝具体的挑食表现有哪些？持续多久了？', NULL, NULL, NULL, '2026-07-10 20:00:30', NOW()),
(1, 'USER', '大概持续了一个月了。特别是绿叶蔬菜，看到就摇头。但是她很喜欢吃水果。', NULL, NULL, NULL, '2026-07-10 20:02:00', NOW()),
(1, 'AI', '喜欢吃水果是个好信号！可以尝试：\n1. 将蔬菜和水果混合制作果蔬泥/果蔬汁\n2. 尝试不同的蔬菜品种，从味道较淡的开始（如南瓜、玉米）\n3. 用可爱的餐具和摆盘吸引注意力\n4. 家长做好榜样，在孩子面前愉快地吃蔬菜\n建议每次只引入一种新蔬菜，坚持10-15次尝试，不要轻易放弃！', true, '很有帮助，我会试试果蔬泥的方法', NULL, '2026-07-10 20:03:00', NOW()),

(2, 'USER', '小樱桃最近不太愿意去幼儿园，说有个小朋友不跟她玩。我该怎么帮助她？', NULL, NULL, NULL, '2026-07-12 21:00:00', NOW()),
(2, 'AI', '孩子遇到社交挫折是很正常的成长经历。您可以：\n1. 倾听并接纳孩子的感受，不要轻视她的困扰\n2. 和老师沟通了解具体情况\n3. 教孩子一些社交技巧，如"我可以一起玩吗？"\n4. 安排幼儿园外的玩耍约会，建立友谊\n5. 通过绘本故事引导孩子理解友谊', NULL, NULL, NULL, '2026-07-12 21:00:30', NOW()),
(2, 'USER', '和老师聊过了，老师说那个小朋友最近和另一个孩子玩得比较好。小樱桃可能觉得被冷落了。', NULL, NULL, NULL, '2026-07-12 21:05:00', NOW()),
(2, 'AI', '理解孩子的感受很重要。您可以：\n1. 帮助小樱桃发展多元的社交圈，不只依赖一个朋友\n2. 和老师商量能否安排一些小组活动，促进不同孩子的互动\n3. 在家通过角色扮演练习社交场景\n4. 增强孩子的自信心，有自信的孩子更容易交到朋友\n5. 可以邀请其他小朋友来家里玩，创造交友机会\n这个阶段的孩子社交圈子正在形成，多一些耐心和引导，情况会慢慢改善的。', true, '角色扮演的方法很好，孩子很喜欢', NULL, '2026-07-12 21:06:00', NOW()),

(3, 'USER', '小樱桃明年就要上小学了，现在需要做哪些准备？', NULL, NULL, NULL, '2026-07-14 19:30:00', NOW()),
(3, 'AI', '幼小衔接是孩子成长的重要阶段，可以从以下几个方面准备：\n1. 学习习惯：培养专注力和倾听能力，逐步延长学习时间\n2. 自理能力：自己穿衣、整理书包、如厕等\n3. 社交能力：学会与同学相处、解决小矛盾\n4. 知识储备：认识一些常用汉字、掌握20以内加减法\n5. 心理准备：通过绘本和参观小学减少陌生感\n您现在最关心的是哪个方面呢？', NULL, NULL, NULL, '2026-07-14 19:31:00', NOW()),
(3, 'USER', '主要是学习习惯方面，她现在坐不住，看电视能看半小时，但看书几分钟就要跑开。', NULL, NULL, NULL, '2026-07-14 19:33:00', NOW()),
(3, 'AI', '培养专注力需要循序渐进：\n1. 从孩子感兴趣的活动开始，如拼图、画画、乐高等\n2. 使用计时器法：从5分钟开始，逐步延长时间\n3. 创造安静无干扰的学习环境\n4. 把学习游戏化，让学习变得有趣\n5. 注意：看电视是被动注意力，和主动学习的专注力不同\n建议每天固定15-20分钟的"学习时间"，坚持下去会有很大改善。您也可以先从她喜欢的绘本开始，慢慢培养阅读习惯。', NULL, NULL, NULL, '2026-07-14 19:35:00', NOW());

